function solve(nums, k) {
    const n = nums.length;
    if (n === 0) {
        return 0;
    }

    // dp[i][0]: maximum score of a valid alternating subsequence ending at index i,
    // where nums[i] is the 'smaller' element (i.e., the previous element was larger).
    // This means the sequence ends with ... > nums[i].
    let dp_smaller = new Array(n).fill(0);

    // dp[i][1]: maximum score of a valid alternating subsequence ending at index i,
    // where nums[i] is the 'larger' element (i.e., the previous element was smaller).
    // This means the sequence ends with ... < nums[i].
    let dp_larger = new Array(n).fill(0);

    let maxScore = 0;

    for (let i = 0; i < n; i++) {
        // Base case: Subsequence of length 1 ending at i.
        dp_smaller[i] = nums[i];
        dp_larger[i] = nums[i];

        // Iterate over all possible previous indices j such that i - j >= k
        for (let j = 0; j < i - k + 1; j++) {
            // Case 1: Ending with ... > nums[i] (nums[i] is smaller than the previous element)
            // The previous element must have been at index j, and it must have been smaller than the one before j,
            // or it was the start of the sequence.
            // The previous element nums[j] must be greater than nums[i].
            if (nums[j] > nums[i]) {
                // We extend a sequence ending at j where nums[j] was the 'larger' element.
                // New score = (Score ending at j, where nums[j] was larger) + nums[i]
                dp_smaller[i] = Math.max(dp_smaller[i], dp_larger[j] + nums[i]);
            }

            // Case 2: Ending with ... < nums[i] (nums[i] is larger than the previous element)
            // The previous element nums[j] must be smaller than nums[i].
            if (nums[j] < nums[i]) {
                // We extend a sequence ending at j where nums[j] was the 'smaller' element.
                // New score = (Score ending at j, where nums[j] was smaller) + nums[i]
                dp_larger[i] = Math.max(dp_larger[i], dp_smaller[j] + nums[i]);
            }
        }

        // Update the overall maximum score
        maxScore = Math.max(maxScore, dp_smaller[i], dp_larger[i]);
    }

    return maxScore;
